item.description:
.article p {
  margin: 0 0 1rem 0;
  line-height: 1.6;
}

.article h2 {
  margin: 2rem 0 1rem;
}

.article img {
  display: block;
  width: 100%;
  height: auto;
  border-radius: 8px;
  margin: 1.5rem 0;
}

.article blockquote {
  border-left: 4px solid #ccc;
  padding: 1rem 1.25rem;
  margin: 2rem 0;
  font-style: italic;
  background: #f8f8f8;
}




